class Solution:
    def numSubarrayBoundedMax(self, nums, left, right):
        n = len(nums)
        total = 0
        for i in range(n):
            mx = 0
            for j in range(i, n):
                if nums[j] > mx:
                    mx = nums[j]
                if left <= mx <= right:
                    total += 1
        return total

