class Solution:
    def numSubarrayBoundedMax(self, nums, left, right):
        total = 0
        start = -1
        last_in = -1
        for i, v in enumerate(nums):
            if v > right:
                start = i
                last_in = -1
            elif v >= left:
                last_in = i
            if last_in != -1:
                total += last_in - start
        return total

