var numSubarrayBoundedMax = function(nums, left, right) {
    let total = 0;
    let start = -1;
    let lastIn = -1;
    for (let i = 0; i < nums.length; i++) {
        const v = nums[i];
        if (v > right) {
            start = i;
            lastIn = -1;
        } else if (v >= left) {
            lastIn = i;
        }
        if (lastIn !== -1) total += lastIn - start;
    }
    return total;
};
